// ── BrandFlow: Build Claude Prompt ──────────────────────────────────────
// Reads already-stored articles from n8n static data and the freshly
// fetched base articles so Claude avoids duplicating existing titles.

const fetchResponse = $input.first().json;
const baseArticles = Array.isArray(fetchResponse.articles) ? fetchResponse.articles : [];

// Load articles generated in previous weekly runs (persisted in n8n)
const staticData = $getWorkflowStaticData('global');
const storedArticles = Array.isArray(staticData.generatedArticles)
  ? staticData.generatedArticles
  : [];

// Build "avoid duplicate" list from all known titles
const allTitles = [...storedArticles, ...baseArticles]
  .map(a => a.title)
  .filter(Boolean);

const avoidList = allTitles.length > 0
  ? allTitles.map(t => `- ${t}`).join('\n')
  : '(none yet — write a fresh article)';

const prompt = `You write insight articles for BrandFlow, a South African digital agency 
helping SMEs automate their business operations.

Generate ONE new insight article. Requirements:
- Relevant to South African SMEs (reference local context where natural)
- Practical and actionable for business owners and managers
- Category MUST be exactly one of: "Getting Started", "Case Study", "Compliance", "Tools"
- Topics: n8n automation, POPIA compliance, workflow optimisation, ROI, 
  reducing admin overhead, integrating local business tools

Already published — do NOT duplicate these:
${avoidList}

Respond with ONLY a valid JSON object. No markdown fences. No explanation:
{
  "title": "concise headline under 70 characters",
  "excerpt": "1–2 sentence hook for the reader, max 180 characters",
  "category": "Getting Started|Case Study|Compliance|Tools",
  "readTime": "N min read",
  "slug": "url-safe-slug",
  "tags": ["tag1", "tag2", "tag3"]
}`;

return [{ json: { prompt, baseArticles, storedArticles } }];

// ── BrandFlow: Parse Claude Response & Store Article ─────────────────────
// Parses the JSON article Claude returned, assigns the next sequential ID,
// then prepends it to the n8n static data store so it persists across runs.

const claudeResponse = $input.first().json;
const rawText = claudeResponse.content?.[0]?.text ?? '';

if (!rawText) throw new Error('Claude API returned empty content — check your API key and model name.');

// Strip markdown code fences if Claude wrapped the JSON
const cleaned = rawText
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/\s*```$/i, '')
  .trim();

let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (e) {
  throw new Error(`Claude did not return valid JSON.\nRaw: ${rawText.substring(0, 300)}`);
}

// Pull context set by Build Claude Prompt
const ctx = $('Build Claude Prompt').first().json;
const storedArticles = Array.isArray(ctx.storedArticles) ? ctx.storedArticles : [];
const baseArticles = Array.isArray(ctx.baseArticles) ? ctx.baseArticles : [];

// Determine next sequential ID across all known articles
const allIds = [...storedArticles, ...baseArticles]
  .map(a => parseInt((a.id || 'art-000').replace('art-', ''), 10))
  .filter(n => !isNaN(n));
const maxId = allIds.length > 0 ? Math.max(...allIds) : 0;
const nextId = 'art-' + String(maxId + 1).padStart(3, '0');

// Sanitise slug
const rawSlug = String(parsed.slug || parsed.title || nextId);
const slug = rawSlug
  .toLowerCase()
  .replace(/[^a-z0-9-]/g, '-')
  .replace(/-+/g, '-')
  .replace(/^-|-$/g, '')
  .substring(0, 80);

// Validate category
const validCategories = ['Getting Started', 'Case Study', 'Compliance', 'Tools'];
const category = validCategories.includes(parsed.category)
  ? parsed.category
  : 'Getting Started';

const newArticle = {
  id: nextId,
  title: String(parsed.title || '').trim(),
  excerpt: String(parsed.excerpt || '').trim(),
  category,
  readTime: parsed.readTime || '5 min read',
  publishedAt: new Date().toISOString().split('T')[0],
  slug,
  featured: false,
  tags: Array.isArray(parsed.tags) ? parsed.tags : []
};

// Persist in n8n static data (survives between workflow executions)
const staticData = $getWorkflowStaticData('global');
if (!Array.isArray(staticData.generatedArticles)) staticData.generatedArticles = [];
staticData.generatedArticles = [newArticle, ...staticData.generatedArticles];

return [{
  json: {
    success: true,
    articleId: newArticle.id,
    title: newArticle.title,
    publishedAt: newArticle.publishedAt,
    totalStored: staticData.generatedArticles.length
  }
}];

// ── BrandFlow: Build Article Response ────────────────────────────────────
// Merges AI-generated articles (stored in n8n static data across weekly runs)
// with the base articles served by the cPanel PHP endpoint.
// Deduplicates by slug, sorts newest-first, returns the combined feed.

const fetchResponse = $input.first().json;
const baseArticles = Array.isArray(fetchResponse.articles) ? fetchResponse.articles : [];

// Load all previously generated articles persisted in n8n
const staticData = $getWorkflowStaticData('global');
const storedArticles = Array.isArray(staticData.generatedArticles)
  ? staticData.generatedArticles
  : [];

// Merge: stored (newest AI-generated) first, then base (static JSON)
// Deduplicate by slug then by id
const seen = new Set();
const allArticles = [];

for (const article of [...storedArticles, ...baseArticles]) {
  const key = article.slug || article.id;
  if (key && !seen.has(key)) {
    seen.add(key);
    allArticles.push(article);
  }
}

// Sort newest publishedAt first
allArticles.sort((a, b) => {
  const da = new Date(a.publishedAt || 0).getTime();
  const db = new Date(b.publishedAt || 0).getTime();
  return db - da;
});

return [{
  json: {
    success: true,
    source: 'n8n-brandflow-insights',
    updatedAt: new Date().toISOString(),
    count: allArticles.length,
    articles: allArticles
  }
}];
